import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';
import { invoke } from './dist/llm/CLIInvoker.js';

async function testImageLogic() {
    console.log("Starting QA Logic Verification...");

    const testImage = "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==";

    // We simulate an invoke call. 
    // Since we don't have the real CLI installed that supports --file in this env, 
    // we expect it to fail at 'spawn' or 'which', but we want to check if files are created and parameters are built.

    const options = {
        attachments: [{ type: 'image', url: testImage }]
    };

    try {
        console.log("Testing invoke with 1 attachment...");
        // This will likely throw because 'claude' isn't in PATH or doesn't support --file here,
        // but the 'saveTempImage' happens before the spawn.
        await invoke('claude', 'test prompt', options);
    } catch (err) {
        console.log("Caught expected error or status:", err.message);
    }

    const tempDir = path.join(os.tmpdir(), 'colony-attachments');
    if (fs.existsSync(tempDir)) {
        const files = fs.readdirSync(tempDir);
        console.log(`Current files in temp dir: ${files.length}`);
        if (files.length === 0) {
            console.log("✅ Cleanup verified: No files left in temp dir.");
        } else {
            console.log("❌ Cleanup failed: Files remaining in temp dir.");
        }
    } else {
        console.log("✅ Temp dir does not exist or was cleaned up.");
    }
}

testImageLogic().catch(console.error);

